export const IE_100 = [
  // ==================== EASY (30) ====================
  {id:"ie-201",d:"easy",t:"Inclusive Education",q:"Inclusive Education includes which learners together in mainstream schools?",c:["A. Only learners with disabilities","B. Only gifted and talented learners","C. Both non-disabled and people with disability","D. Only learners without disabilities"],a:"C",e:"Inclusive Education includes BOTH NON-DISABLED and PEOPLE WITH DISABILITY learning TOGETHER in mainstream schools, colleges, and universities."},
  {id:"ie-202",d:"easy",t:"WHO Classification",q:"WHO's classification places DISABILITY at which level?",c:["A. Body level — physical or mental defect","B. TASK level — person-level limitations in performing activities","C. Situation level — problem during interaction with environment","D. Community level — social participation limitations"],a:"B",e:"DISABILITY = TASK LEVEL — person-level limitations in PHYSICAL AND PSYCHO-COGNITIVE ACTIVITIES or impairment that limits the ability to PERFORM CERTAIN TASKS. It is the result of an impairment."},
  {id:"ie-203",d:"easy",t:"Paradigms of Disability",q:"The Social Model views disability as caused by:",c:["A. Intrinsic individual impairment — a deficiency within the person","B. Genetic factors that cannot be changed","C. SOCIETAL BARRIERS that must be removed","D. Medical conditions requiring treatment"],a:"C",e:"SOCIAL MODEL = SOCIETAL BARRIERS. The solution is to REMOVE BARRIERS and ADJUST THE ENVIRONMENT. Responsibility = EVERYONE."},
  {id:"ie-204",d:"easy",t:"Legal Bases",q:"RA 11650 mandates that ALL PUBLIC SCHOOLS nationwide are required to:",c:["A. Build separate special education buildings","B. IDENTIFY learners with special needs and PROVIDE FREE BASIC AND QUALITY EDUCATION","C. Hire only special education teachers for inclusive classes","D. Replace traditional teaching with therapeutic interventions"],a:"B",e:"RA 11650 requires all public schools to: (1) IDENTIFY learners with special needs and (2) PROVIDE FREE BASIC AND QUALITY EDUCATION to these learners."},
  {id:"ie-205",d:"easy",t:"IDEA",q:"FAPE stands for:",c:["A. Free and Appropriate Public Evaluation","B. Free Appropriate Public Education","C. Funded Academic Program for Everyone","D. Federal Act for Public Education"],a:"B",e:"FAPE = FREE APPROPRIATE PUBLIC EDUCATION — guaranteed by IDEA to all disabled children. Education at public expense, without charge, that meets the child's unique needs."},
  {id:"ie-206",d:"easy",t:"IDEA Disability Categories",q:"The 'Triad of Impairment' describes which IDEA disability category?",c:["A. Intellectual Disability","B. ADHD","C. Autism Spectrum Disorder","D. Emotional Disturbance"],a:"C",e:"AUTISM = TRIAD OF IMPAIRMENT: (1) Impaired COMMUNICATION, (2) Impaired SOCIAL SKILLS, (3) Restricted and REPETITIVE WAY OF BEING-IN-THE-WORLD."},
  {id:"ie-207",d:"easy",t:"Learning Disabilities",q:"Which learning disability specifically affects READING and language-based processing?",c:["A. Dyscalculia","B. Dysgraphia","C. Dyslexia","D. ADHD"],a:"C",e:"DYSLEXIA = affects READING and LANGUAGE-BASED PROCESSING SKILLS. Dyscalculia = math. Dysgraphia = handwriting/fine motor."},
  {id:"ie-208",d:"easy",t:"IEP",q:"An Individualized Education Plan (IEP) creates:",c:["A. Standardized curricula for all students with disabilities","B. PERSONALIZED learning plans for children with special needs","C. Group learning programs for students in special schools","D. Medical treatment plans for students with disabilities"],a:"B",e:"IEP = creates PERSONALIZED LEARNING PLANS for children with SPECIAL NEEDS — individualized goals, strategies, and support team."},
  {id:"ie-209",d:"easy",t:"Co-teaching Models",q:"In ONE TEACH, ONE DRIFT, the drifting teacher:",c:["A. Observes and collects data on student behavior","B. Teaches a smaller group at a different level","C. Provides ASSISTANCE to learners while the other teacher teaches","D. Teaches one of two divided groups simultaneously"],a:"C",e:"ONE TEACH, ONE DRIFT: one teacher teaches, the other DRIFTS (provides ASSISTANCE to individual learners)."},
  {id:"ie-210",d:"easy",t:"Co-teaching Models",q:"Which co-teaching model divides the class into TWO GROUPS taught simultaneously by both teachers delivering the SAME LESSON?",c:["A. Station Teaching","B. Alternative Teaching","C. Team Teaching","D. Parallel Teaching"],a:"D",e:"PARALLEL TEACHING: class divided into TWO GROUPS, BOTH teachers SIMULTANEOUSLY deliver THE SAME LESSON to each group."},
  {id:"ie-211",d:"easy",t:"Action Research",q:"Action Research was coined by Kurt Lewin in 1944. It is about ACTION and RESEARCH. What does the RESEARCH aspect involve?",c:["A. Making changes to improve practice","B. FINDING THINGS OUT and coming to a new understanding that creates new knowledge","C. Following theoretical problems defined by pure researchers","D. Statistical analysis of large datasets"],a:"B",e:"RESEARCH aspect = FINDING THINGS OUT and coming to a NEW UNDERSTANDING that creates NEW KNOWLEDGE."},
  {id:"ie-212",d:"easy",t:"4Cs of Action Research",q:"Which 4C requires research to be RELEVANT, ORIGINAL, and GENERALIZABLE?",c:["A. Credible","B. Communicable","C. Contributory","D. Conforming"],a:"C",e:"CONTRIBUTORY = RELEVANT (interesting, applicable, current), ORIGINAL (original idea, procedure, result), GENERALIZABLE (externally valid)."},
  {id:"ie-213",d:"easy",t:"Accommodations",q:"ACCOMMODATIONS in inclusive education change _____ without changing the content or academic standards.",c:["A. The curriculum content","B. The academic difficulty level","C. HOW students access and demonstrate understanding","D. The learning objectives"],a:"C",e:"ACCOMMODATIONS = change HOW students ACCESS and DEMONSTRATE UNDERSTANDING without changing the CONTENT, ACADEMIC STANDARDS, or CURRICULUM."},
  {id:"ie-214",d:"easy",t:"Intellectual Disability",q:"A student with Profound Intellectual Disability (IQ below 20-25) requires which level of support?",c:["A. Independent — can function without assistance","B. Supervised — requires regular guidance","C. Dependent — requires continuous care","D. Custodial — under hospital/institutional care"],a:"D",e:"PROFOUND ID (IQ below 20-25) = CUSTODIAL — under hospital care. Severe (IQ 20-25 to 34-39) = DEPENDENT. Moderate = SUPERVISED. Mild = INDEPENDENT."},
  {id:"ie-215",d:"easy",t:"Legal Bases",q:"Batas Pambansa 344 specifically covers accessibility for which physical features?",c:["A. Schools only","B. Hospitals only","C. Pathwalks, sidewalks, elevators, comfort rooms, rails, hallways, and ramps","D. Only public transportation"],a:"C",e:"BP 344 (Accessibility Law) covers: pathwalks, sidewalks, elevators, COMFORT ROOMS, rails, HALLWAYS, and RAMPS — all physical features that affect the mobility of disabled persons."},
  {id:"ie-216",d:"easy",t:"Hearing Impairment",q:"Which type of hearing loss results from damage to the INNER EAR or AUDITORY NERVE and is PERMANENT?",c:["A. Conductive Hearing Loss","B. Mixed Hearing Loss","C. Central Hearing Loss","D. Sensorineural Hearing Loss"],a:"D",e:"SENSORINEURAL HEARING LOSS = result of damaged INNER EAR or AUDITORY NERVE. It is PERMANENT hearing loss — cannot be corrected by addressing the outer/middle ear."},
  {id:"ie-217",d:"easy",t:"ADHD",q:"The COMBINED type of ADHD combines which two other types?",c:["A. Auditory and Visual processing types","B. Inattentive and Hyperactive-Impulsive types","C. Cognitive and Behavioral types","D. Social and Academic types"],a:"B",e:"COMBINED ADHD = combination of INATTENTIVE (daydreamy, loses things, difficulty following instructions) AND HYPERACTIVE-IMPULSIVE (fidgeting, interrupting, acting without thinking) characteristics."},
  {id:"ie-218",d:"easy",t:"Mainstreaming vs. Inclusion",q:"In MAINSTREAMING, students with disabilities are EXPECTED to:",c:["A. Follow a completely different curriculum from peers","B. Attend only special education programs","C. MEET THE SAME ACADEMIC STANDARDS as every other student","D. Not participate in any regular classroom activities"],a:"C",e:"MAINSTREAMING: students ARE EXPECTED to MEET THE SAME ACADEMIC STANDARDS. INCLUSION: students are NOT expected to meet the same standards — the key distinction."},
  {id:"ie-219",d:"easy",t:"Action Research Characteristics",q:"Action Research is PARTICIPATIVE because:",c:["A. It requires participation from government agencies","B. TEACHERS AND LEARNERS are CO-RESEARCHERS","C. It involves public participation in research design","D. Results are shared with all participants"],a:"B",e:"PARTICIPATIVE = TEACHERS AND LEARNERS ARE CO-RESEARCHERS. Those inside the school actively participate in the research process — it is democratic, inside-out inquiry."},
  {id:"ie-220",d:"easy",t:"Inclusive Practice",q:"INCLUSIVE PRACTICE refers to:",c:["A. Special education programs in segregated settings","B. ATTITUDES AND METHODS that ensure all learners can access mainstream education in the LEAST RESTRICTIVE ENVIRONMENT","C. Medical rehabilitation programs for disabled students","D. Standardized curricula for students with disabilities"],a:"B",e:"INCLUSIVE PRACTICE = ATTITUDES AND METHODS that ensure ALL LEARNERS can access mainstream education, and that STUDENTS RECEIVE THEIR EDUCATION IN THE LEAST RESTRICTIVE ENVIRONMENT (LRE)."},
  {id:"ie-221",d:"easy",t:"Deaf-Blindness",q:"The famous person associated with DEAF-BLINDNESS who learned to communicate with the help of Anne Sullivan is:",c:["A. Nelson Mandela","B. Thomas Edison","C. Helen Keller","D. Albert Einstein"],a:"C",e:"HELEN KELLER is the most famous person with Deaf-Blindness — she learned to communicate with the help of her teacher ANNE SULLIVAN. Deaf-Blindness = SIMULTANEOUS hearing AND visual impairments."},
  {id:"ie-222",d:"easy",t:"Action Research",q:"Nelson (2014)'s Action Research cycle is known as ORPA. What does ORPA stand for?",c:["A. Observe, Research, Plan, Adjust","B. Organize, Reflect, Practice, Analyze","C. Observe, Reflect, Plan, Act","D. Outcome, Review, Process, Action"],a:"C",e:"ORPA = OBSERVE → REFLECT → PLAN → ACT (then back to Observe). Nelson (2014)'s cyclical action research process."},
  {id:"ie-223",d:"easy",t:"IDEA Disability",q:"MUSCULAR DYSTROPHY is characterized by:",c:["A. Abnormal fragility of bones","B. Incomplete formation of the spine","C. Involuntary jerking movements and spastic muscles","D. DETERIORATION AND WASTING OF MUSCLE FIBERS — a neuromuscular condition"],a:"D",e:"MUSCULAR DYSTROPHY = neuromuscular condition characterized by DETERIORATION AND WASTING OF MUSCLE FIBERS — a progressive disease."},
  {id:"ie-224",d:"easy",t:"Emotional Disturbance",q:"OBSESSIVE-COMPULSIVE DISORDER (OCD) is described as involving:",c:["A. Fear of gaining weight","B. Eating non-food items","C. Uncontrolled mood swings","D. TOO MUCH ORDER — excessive need for order, control, and repetitive behaviors"],a:"D",e:"OCD = too much order/excessive control — classified under EMOTIONAL DISTURBANCE in IDEA. Characterized by obsessive thoughts and compulsive behaviors."},
  {id:"ie-225",d:"easy",t:"Reasonable Accommodation",q:"Reasonable Accommodation must NOT impose which condition?",c:["A. Changes on the curriculum","B. Lower academic standards","C. UNDUE BURDEN on the service provider","D. Modifications to the physical environment"],a:"C",e:"REASONABLE ACCOMMODATION = modifications or adjustments made, NOT IMPOSING UNDUE BURDEN, that enable individuals with disabilities to participate fully."},
  {id:"ie-226",d:"easy",t:"IEP Components",q:"The STRATEGIES component of an IEP includes:",c:["A. Specific aspirations for the child's school year","B. Parents, teachers, therapists, and caregivers","C. METHODS to address the child's strengths, weaknesses, and learning styles","D. The type of classroom (regular or special) for delivery"],a:"C",e:"IEP STRATEGIES = METHODS to address the child's STRENGTHS, WEAKNESSES, AND LEARNING STYLES — the 'how' of the individualized education plan."},
  {id:"ie-227",d:"easy",t:"IDEA Orthopedic",q:"CEREBRAL PALSY is classified as which IDEA category?",c:["A. Learning Disabilities","B. Emotional Disturbance","C. Other Health Impairments","D. Orthopedic Impairment"],a:"D",e:"CEREBRAL PALSY = ORTHOPEDIC IMPAIRMENT — problems in bones, muscles, and joints. Characterized by involuntary jerking movements, spastic muscles, poor balance, and speech impairment."},
  {id:"ie-228",d:"easy",t:"Action Research",q:"Action Research is FUTURE-ORIENTED because it:",c:["A. Documents historical teaching practices","B. Predicts future academic performance using statistics","C. SEEKS SOLUTION TO A CURRENT PROBLEM FOR FUTURE IMPROVEMENT","D. Creates theory applicable to future research only"],a:"C",e:"FUTURE-ORIENTED = Action Research seeks SOLUTION to a CURRENT PROBLEM FOR FUTURE IMPROVEMENT. It is forward-looking, aimed at improving FUTURE PRACTICE."},
  {id:"ie-229",d:"easy",t:"Salamanca Statement",q:"The Salamanca Statement of June 1994 affirms the right to education of EVERY INDIVIDUAL regardless of:",c:["A. Academic ability only","B. INDIVIDUAL DIFFERENCES — within the regular education system","C. Whether they have a disability certificate","D. Their socioeconomic background only"],a:"B",e:"Salamanca Statement affirms the right to education of EVERY INDIVIDUAL regardless of INDIVIDUAL DIFFERENCES — within the REGULAR EDUCATION SYSTEM."},
  {id:"ie-230",d:"easy",t:"RA 7277",q:"Republic Act 7277 is known as the:",c:["A. Accessibility Law","B. Education Act of 1982","C. MAGNA CARTA FOR DISABLED PERSONS","D. Inclusive Education Act"],a:"C",e:"RA 7277 = MAGNA CARTA FOR DISABLED PERSONS — outlines the numerous rights that a disabled person is entitled to. Amended by RA 9442."},

  // ==================== MODERATE (50) ====================
  {id:"ie-231",d:"moderate",t:"Inclusive vs. Special Needs",q:"A school transitions from SPED to Inclusive Education. A teacher asks: 'Do students with severe disabilities benefit from inclusion?' The MOST EVIDENCE-BASED answer is:",c:["A. No — severe disabilities require exclusive special school placement","B. Only mild disabilities benefit from inclusion","C. YES — research consistently shows that students with severe disabilities benefit from inclusive settings through social exposure, peer modeling, and access to general education content, when appropriate supports are in place","D. Only students whose disabilities match the Mild classification benefit"],a:"C",e:"Evidence supports inclusion for students with SEVERE disabilities when APPROPRIATE SUPPORTS are provided (IEP, co-teaching, accommodations). Benefits: social interaction, peer modeling, access to grade-level content, and community integration preparation."},
  {id:"ie-232",d:"moderate",t:"WHO and Social Model Application",q:"A municipality installs RAMPS, ACCESSIBLE RESTROOMS, and SIGN LANGUAGE INTERPRETERS in public offices. From WHO's perspective, these changes target which level of disability?",c:["A. Impairment level — reducing the physical defect","B. Disability level — improving task performance ability","C. HANDICAP LEVEL — removing environmental barriers that create disadvantage during interaction with the environment","D. Rehabilitation level — medical treatment of conditions"],a:"C",e:"RAMPS, ACCESSIBLE RESTROOMS, SIGN LANGUAGE INTERPRETERS = removing ENVIRONMENTAL BARRIERS = addressing HANDICAP LEVEL (situation). The Social Model solution: remove societal barriers that create handicaps — not change the impairment or disability."},
  {id:"ie-233",d:"moderate",t:"IDEA Application",q:"A student is diagnosed with BIPOLAR DISORDER causing extreme mood swings that disrupt her academic performance. Under IDEA, which category applies and what is the educational implication?",c:["A. Other Health Impairments — ADHD related","B. EMOTIONAL DISTURBANCE — the IEP must address both ACADEMIC and BEHAVIORAL/EMOTIONAL support needs","C. Multiple Disabilities — must combine multiple categories","D. Intellectual Disability — mood affects cognitive processing"],a:"B",e:"BIPOLAR DISORDER = EMOTIONAL DISTURBANCE under IDEA. Educational implication: IEP must address BOTH academic support AND behavioral/emotional regulation strategies. Emotional disturbance affects school performance — the IEP must be comprehensive."},
  {id:"ie-234",d:"moderate",t:"Accommodation Application",q:"A student with visual impairment in Grade 5 is given extra time to complete tests, large-print exam papers, and allowed to use a magnifier. The CONTENT of the test is identical to all other students. These are all examples of:",c:["A. Modifications — the academic standard is lowered","B. Adaptations — significant change in content and products","C. IEP Goals — specific aspirations for the school year","D. ACCOMMODATIONS — changes in format/access without changing content or standards"],a:"D",e:"ACCOMMODATIONS — extra time, large print, magnifier = changes in HOW the student accesses and demonstrates knowledge WITHOUT CHANGING the CONTENT or ACADEMIC STANDARD. Same test, different access format."},
  {id:"ie-235",d:"moderate",t:"Co-teaching Application",q:"Two teachers collaborate for an English class. Teacher A teaches vocabulary directly to the larger group. Teacher B simultaneously teaches a smaller group of students who need intensive reading support at a lower level. Which model is this?",c:["A. Team Teaching — both teachers work with all students","B. Parallel Teaching — same content to two groups","C. Alternative Teaching — ONE teacher with LARGER GROUP, other with SMALLER GROUP at DIFFERENT LEVEL","D. Station Teaching — students rotate through stations"],a:"C",e:"ALTERNATIVE TEACHING — Teacher A teaches the LARGER GROUP, Teacher B teaches the SMALLER GROUP at a DIFFERENT LEVEL (intensive support). The two groups work on DIFFERENT content or at different complexity levels simultaneously."},
  {id:"ie-236",d:"moderate",t:"IEP Development Process",q:"A teacher notices a student struggling significantly and suspects a disability. What is the FIRST STEP in the IEP Development Process?",c:["A. Immediately develop the IEP goals","B. Place the student in a special classroom","C. REFERRAL AND EVALUATION — identify learning challenges and potential special needs through assessment","D. Contact parents and inform them of the disability diagnosis"],a:"C",e:"FIRST STEP: REFERRAL AND EVALUATION — identifying learning challenges and potential special needs. THEN: IEP Development (collaborative planning). THEN: Implementation (putting the plan into action). Evaluation comes BEFORE developing goals."},
  {id:"ie-237",d:"moderate",t:"Action Research ORPA Application",q:"A PE teacher notices students with physical disabilities cannot fully participate in traditional sports (OBSERVE). She reflects on ways to modify activities for inclusion (REFLECT). She designs adapted physical education activities (PLAN). She implements the adapted activities (ACT). After implementation, she collects new data. Which step follows?",c:["A. Publish the findings in a journal","B. Stop — the cycle is complete after one ORPA","C. OBSERVE AGAIN — the cycle repeats as new data triggers another reflection-plan-act cycle","D. Present to the principal and request funding"],a:"C",e:"ORPA is CYCLICAL — after ACT, the teacher OBSERVES AGAIN. New data triggers new REFLECTION → new PLAN → new ACTION. The cycle continues until the problem is satisfactorily resolved."},
  {id:"ie-238",d:"moderate",t:"4Cs Application",q:"A teacher writes her action research report in clear, simple language so that other teachers in the school can easily read and apply the findings. She also posts it on the school bulletin board so all can access it. This satisfies which 4C?",c:["A. Credible — rigorous and transparent","B. COMMUNICABLE — CONSUMABLE (readable, understandable) and ACCESSIBLE (available to those who need it)","C. Contributory — relevant and original","D. Conforming — ethical and aligned with regulations"],a:"B",e:"COMMUNICABLE = CONSUMABLE (clear, simple language = structured and readable) + ACCESSIBLE (posted on bulletin board = easily available to the group being studied). Both sub-criteria of Communicable are addressed."},
  {id:"ie-239",d:"moderate",t:"Autism Teaching",q:"A teacher works with a student with ASD who becomes overwhelmed by loud classroom noise. Which FIRST PRIORITY teaching strategy should the teacher implement?",c:["A. Give the student more academic tasks to focus attention","B. Remove the student from all activities when overwhelmed","C. MINIMIZE SENSES — reduce sensory input (noise, visual clutter) because students with ASD have difficulty concentrating with sensory overload","D. Require the student to tolerate the noise as part of social skills training"],a:"C",e:"MINIMIZE SENSES = FIRST PRIORITY for ASD — these children have difficulty concentrating due to sensory sensitivity. Reducing sensory overload (noise, visual clutter) is the FIRST step before introducing any academic content."},
  {id:"ie-240",d:"moderate",t:"Legal Framework Application",q:"A blind student demands Braille textbooks from her school, citing RA 11650. The school says Braille textbooks are too expensive. From a legal standpoint:",c:["A. The school's budget constraints exempt it from providing Braille materials","B. The student must accept printed textbooks with a reader instead","C. RA 11650 requires ALL PUBLIC SCHOOLS to provide free basic and quality education to learners with disabilities — Braille materials may be accessed through ILRC or DepEd resources; financial constraints do not exempt the school from this legal obligation","D. Braille textbooks are optional accommodations under Philippine law"],a:"C",e:"RA 11650 creates a LEGAL OBLIGATION for free, quality, APPROPRIATE education for learners with disabilities. The ILRC is specifically designed to provide SUPPORT AND RESOURCES (like materials) to schools. The school must find solutions — DepEd resources, ILRC, or adapted materials."},
  {id:"ie-241",d:"moderate",t:"Intellectual Disability and Down Syndrome",q:"A student with Down Syndrome (Trisomy 21) has an IQ of 48 and requires supervision for daily tasks. Under intellectual disability classification, she has MODERATE ID. Which educational approach is MOST APPROPRIATE?",c:["A. Place exclusively in a special school with no regular classroom access","B. Full inclusion with no additional supports","C. SUPERVISED inclusion — meaningful participation in inclusive settings with appropriate supports, adapted curriculum (modification), and one-on-one support when needed","D. Custodial care with no academic expectations"],a:"C",e:"MODERATE ID = SUPERVISED. Educational approach: SUPERVISED INCLUSION with: (1) appropriate supports (para-educator), (2) MODIFIED curriculum (lowered complexity), (3) one-on-one instruction, (4) hands-on learning. Inclusive setting with individualized supports — not full segregation."},
  {id:"ie-242",d:"moderate",t:"Co-teaching Model Comparison",q:"A principal asks: 'Which co-teaching model is BEST?' The MOST APPROPRIATE response is:",c:["A. Team Teaching — always the best because both teachers are fully active","B. One Teach, One Observe — always best for data collection","C. NO SINGLE MODEL IS ALWAYS BEST — effective co-teaching requires choosing the model based on LESSON GOALS, STUDENT NEEDS, and available resources. Different lessons call for different models","D. Parallel Teaching — always best because it reduces class size"],a:"C",e:"NO SINGLE CO-TEACHING MODEL IS UNIVERSALLY BEST. Different situations call for different models: One Teach/Observe (data needs), Parallel (size reduction), Station (different topics), Alternative (differentiated levels), Team (collaborative delivery). The model should match the LESSON GOAL AND STUDENT NEEDS."},
  {id:"ie-243",d:"moderate",t:"Accommodation vs. Modification Distinction",q:"The CRITICAL DISTINCTION between Accommodation and Modification is that Accommodation:",c:["A. Changes WHAT is learned while Modification changes HOW it is accessed","B. Lowers expectations while Modification maintains them","C. Changes HOW students access and demonstrate learning WITHOUT changing WHAT is required; Modification CHANGES the content or standard itself","D. Applies only to students with severe disabilities; Modification applies to all"],a:"C",e:"KEY DISTINCTION: ACCOMMODATION = changes HOW (format, time, setting, tools) WITHOUT changing WHAT (content, standards, objectives). MODIFICATION = changes WHAT (content, difficulty level, standards). Understanding this distinction prevents mislabeling and ensures appropriate supports."},
  {id:"ie-244",d:"moderate",t:"Action Research Credibility",q:"A teacher's action research shows improvement in student reading after implementing a new strategy. A colleague challenges: 'How do you know the improvement is from your strategy and not from students maturing naturally?' This challenge questions which Credibility sub-criterion?",c:["A. Transparent — research procedures weren't clear","B. Consistent — argument isn't coherent","C. RIGOROUS specifically INTERNALLY VALID — the challenge is about whether the research design can attribute improvement to the strategy (not maturation or other factors)","D. Accessible — results aren't widely available"],a:"C",e:"INTERNAL VALIDITY (sub-criterion of RIGOROUS/CREDIBLE) — can the improvement be ATTRIBUTED TO THE STRATEGY? Alternative explanations (maturation, history effects) threaten internal validity. Single-group pre-post designs are weak on internal validity; this is a classic critique."},
  {id:"ie-245",d:"moderate",t:"RA 10524 Employment",q:"A large hospital (250 employees) with zero PWD employees argues: 'We need all able-bodied staff for safety reasons.' Under RA 10524, the MOST APPROPRIATE response to the hospital is:",c:["A. The hospital is exempt due to safety concerns","B. The hospital must employ PWDs immediately or face criminal prosecution","C. RA 10524 INCENTIVIZES (not legally mandates) corporations to include at least 1% PWDs; many hospital roles (records, administration, counseling) can be performed by PWDs. The hospital should explore which positions are suitable and apply for incentives","D. Safety concerns override all PWD employment laws"],a:"C",e:"RA 10524 INCENTIVIZES (not mandatory for private companies — reserved positions in government). The hospital should identify SUITABLE POSITIONS for PWDs — administrative, records, counseling, laboratory tech — where safety is not compromised. The 1% target and incentives are the mechanism."},
  {id:"ie-246",d:"moderate",t:"Speech or Language Impairment",q:"A student who STUTTERS frequently has difficulty completing oral presentations. Under IDEA, this falls under SPEECH OR LANGUAGE IMPAIRMENT. The MOST APPROPRIATE accommodation is:",c:["A. Excuse the student from all oral activities permanently","B. Reduce grading expectations for the student's speech quality","C. Allow extended time, alternative presentation formats (written or recorded), and speech therapy support — maintaining content standards while removing speech mechanics as an access barrier","D. Place the student in a special classroom for all instruction"],a:"C",e:"SPEECH IMPAIRMENT accommodation: Extended time, ALTERNATIVE FORMATS (written or recorded = accommodation, not modification), speech therapy. Content standards maintained. The disability is in speech MECHANICS, not knowledge — accommodations remove the speech mechanics barrier without changing content requirements."},
  {id:"ie-247",d:"moderate",t:"Inclusive Learning Resource Center",q:"RA 11650 requires ILRC in all cities and municipalities. A city has one ILRC. A school in a remote barangay asks: 'How can the ILRC help us if we are far away?' The ILRC's VIRTUAL CENTER provision addresses this because:",c:["A. ILRC only operates physically within 5 km radius","B. Remote schools must build their own ILRC","C. The ILRC can be a VIRTUAL CENTER — providing SUPPORT THROUGH DIGITAL MEANS (online consultancy, digital resources, virtual training) to schools in remote areas without physical access to the ILRC building","D. Remote schools are exempt from RA 11650"],a:"C",e:"RA 11650: ILRC can be a PHYSICAL OR VIRTUAL CENTER. VIRTUAL provision allows the ILRC to support REMOTE SCHOOLS through digital consultancy, online resources, and virtual training — extending ILRC services beyond geographic proximity."},
  {id:"ie-248",d:"moderate",t:"Emotional Disturbance Teaching",q:"A student with ANXIETY DISORDER (classified under Emotional Disturbance) has panic attacks before tests. Which accommodation is MOST DIRECTLY APPROPRIATE?",c:["A. Excuse the student from all assessments permanently","B. Place the student in a separate room ONLY during lunch to reduce social anxiety","C. Provide a quiet testing environment, extended time, allow testing in separate room, regular counseling support — reducing anxiety triggers while maintaining academic standards","D. Increase test frequency to help the student get used to testing"],a:"C",e:"ANXIETY DISORDER accommodations: QUIET TESTING ENVIRONMENT (reduce triggers), EXTENDED TIME (reduce pressure), SEPARATE ROOM (reduce social anxiety triggers), COUNSELING SUPPORT. All maintain academic standards while addressing the disability's impact on assessment performance."},
  {id:"ie-249",d:"moderate",t:"Action Research Conforming Application",q:"A teacher's action research involves students in a marginalized community. The research design inadvertently creates a situation where students in one section benefit from the new strategy while another section does not. An ethics advisor says this violates ETHICAL principles under Conforming. The advisor is CORRECT because:",c:["A. Action research must always benefit all groups equally, and withholding a beneficial strategy from one group while giving it to another is ethically questionable — violating the 'morally justifiable and supporting equal opportunities' criterion of Conforming","B. Differences between sections are acceptable in educational research","C. Conforming only applies to research submitted to journals","D. The advisor is wrong — action research by definition cannot be unethical"],a:"A",e:"CONFORMING/ETHICAL = morally justifiable AND SUPPORTS EQUAL OPPORTUNITIES. Withholding a potentially beneficial strategy from one student group for research purposes is ethically questionable — this violates the 'equal opportunities' and 'morally justifiable' sub-criteria of the Conforming 4C."},
  {id:"ie-250",d:"moderate",t:"Inclusive Classroom Environment Application",q:"A teacher rearranges her classroom to have wider aisles (for wheelchairs), materials accessible at different heights (for varying abilities), and puts student artwork on walls reflecting diverse backgrounds and abilities. Which THREE inclusive classroom guidelines are being applied?",c:["A. Only seating arrangements","B. SEATING ARRANGEMENTS (wide aisles/accessibility), MATERIALS AND ACCOMMODATIONS (accessible heights/adapted materials), and STUDENT OWNERSHIP (diverse artwork reflecting student identities)","C. Only student ownership and organization","D. Only adult language and tone"],a:"B",e:"THREE guidelines applied: SEATING ARRANGEMENTS (wide aisles = accessibility and inclusivity in layout), MATERIALS AND ACCOMMODATIONS (different heights = accessible materials), STUDENT OWNERSHIP (diverse artwork = reflecting student identities and achievements in classroom decorations)."},
  {id:"ie-251",d:"moderate",t:"Multiple Disabilities Distinction",q:"The MOST IMPORTANT distinction between 'Multiple Disabilities' and 'Deaf-Blindness' under IDEA is that:",c:["A. Multiple Disabilities always includes Deaf-Blindness","B. Deaf-Blindness is a separate IDEA category — MULTIPLE DISABILITIES EXPLICITLY DOES NOT INCLUDE DEAF-BLINDNESS","C. Multiple Disabilities is more severe than Deaf-Blindness","D. Both are classified under the same IDEA category"],a:"B",e:"IDEA EXPLICITLY STATES: Multiple Disabilities does NOT include Deaf-Blindness. DEAF-BLINDNESS is a SEPARATE CATEGORY under IDEA. This is an important distinction — students with both hearing and visual impairments are classified under Deaf-Blindness, not Multiple Disabilities."},
  {id:"ie-252",d:"moderate",t:"ADHD Classroom Management",q:"A student with COMBINED ADHD disrupts class constantly. The teacher currently seats the student near the door for quick exits. An inclusion specialist says this is COUNTERPRODUCTIVE. Why?",c:["A. Students with ADHD should not have special seating arrangements","B. The door location is actually DISTRACTING — RA 11650 requires specific accommodations","C. ADHD guidelines recommend seating the student IN FRONT OF THE TEACHER'S DESK — NOT near the door or window. Near the door increases distractions (people passing, noise) and impulsive exits. Front placement = reduced distractions, increased teacher monitoring","D. ADHD students should only be seated at the back"],a:"C",e:"ADHD seating: IN FRONT of teacher's desk = REDUCED DISTRACTIONS (not near door/window). Near the door = MORE distractions (comings and goings), MORE impulsive exits, LESS teacher supervision. The guideline is specific: FRONT placement, AWAY FROM DOOR AND WINDOW."},
  {id:"ie-253",d:"moderate",t:"Inclusive Education Global and Local",q:"The Salamanca Statement (1994) preceded RA 11650 (2022) by 28 years. How does RA 11650 OPERATIONALIZE the principles of the Salamanca Statement in the Philippine context?",c:["A. RA 11650 contradicts the Salamanca principles by requiring special schools","B. RA 11650 OPERATIONALIZES Salamanca by: requiring ALL PUBLIC SCHOOLS to IDENTIFY learners with special needs, provide FREE QUALITY EDUCATION, establish ILRC in all cities/municipalities — translating Salamanca's 'right to regular education with support' into SPECIFIC LEGAL MANDATES","C. RA 11650 replaces Salamanca entirely — the Philippine law is more important","D. The two documents address entirely different issues"],a:"B",e:"RA 11650 OPERATIONALIZES Salamanca: Salamanca's principle (every student has right to education in regular system with whatever support needed) → RA 11650's mandate (all public schools identify + provide free quality education + ILRC support). RA 11650 is the LEGAL IMPLEMENTATION of Salamanca in the Philippines."},
  {id:"ie-254",d:"moderate",t:"IEP and Least Restrictive Environment",q:"An IEP team debates placement for a student with moderate intellectual disability. Option A: Full inclusion with para-educator and modified curriculum. Option B: 70% in special classroom, 30% in regular for PE and arts. Option C: Full-time special school. Using the LRE principle, which option should be TRIED FIRST?",c:["A. Option C — special school provides most specialized care","B. Option B — 70/30 split is a safe compromise","C. OPTION A — LRE requires starting with the MOST INCLUSIVE OPTION that can meet the student's needs. Full inclusion with supports should be tried before moving to more restrictive options","D. The parent decides — LRE is just a preference, not a principle"],a:"C",e:"LRE PRINCIPLE: Start with the MOST INCLUSIVE OPTION (Option A: full inclusion with supports). Only move to more restrictive settings (Options B or C) if the student's needs GENUINELY CANNOT BE MET in the more inclusive setting WITH APPROPRIATE SUPPORTS."},
  {id:"ie-255",d:"moderate",t:"Co-teaching vs. Single Teacher",q:"Research shows that CO-TEACHING generally produces better outcomes than a SINGLE TEACHER in an inclusive classroom. The PRIMARY educational reason is:",c:["A. Two teachers mean half the student-teacher ratio for all activities","B. Co-teachers always have better credentials than single teachers","C. Co-teaching allows SIMULTANEOUS DIFFERENTIATED INSTRUCTION — one teacher can address the needs of students requiring support while the other continues with grade-level content, without removing any students from the classroom","D. Two teachers monitor behavior more effectively, reducing disciplinary issues"],a:"C",e:"CO-TEACHING's educational advantage: SIMULTANEOUS DIFFERENTIATED INSTRUCTION without removal. The classroom remains INCLUSIVE while instruction is differentiated — no students leave the room, but all receive instruction matched to their needs. Single teachers cannot do this alone."},
  {id:"ie-256",d:"moderate",t:"Hearing Impairment Teaching",q:"A teacher of a student with DEAFNESS asks: 'Should I shout louder when speaking to the student?' The MOST APPROPRIATE answer is:",c:["A. Yes — louder voice may help the student hear better","B. Yes — if the hearing aid amplifies sound, louder voice helps","C. NO — students who are DEAF cannot process linguistic information through hearing EVEN WITH AMPLIFICATION. Use VISUAL CUES, SIGN LANGUAGE (if qualified), EYE CONTACT, FACIAL/BODY EXPRESSIONS — not louder voice","D. Yes — shouting combined with sign language is the standard approach"],a:"C",e:"DEAFNESS = CANNOT PROCESS LINGUISTIC INFORMATION THROUGH HEARING, EVEN WITH AMPLIFICATION. Louder voice is useless and may startle. Correct strategies: SIGN LANGUAGE, VISUAL CUES, EYE CONTACT, DEMONSTRATE rather than explain, FACIAL AND BODY EXPRESSIONS, PAPER AND PEN communication."},
  {id:"ie-257",d:"moderate",t:"Action Research Systemic Impact",q:"A teacher's action research on cooperative learning improves outcomes in her class. She shares findings at a faculty meeting, inspiring 5 other teachers to try the same approach. This spread of action research findings is MOST CONSISTENT with which 4C?",c:["A. Credible — the research is rigorous","B. CONTRIBUTORY specifically GENERALIZABLE — the research findings are APPLICABLE (being tried by others) and moving toward being EXTERNALLY VALID as multiple teachers test it in different classrooms","C. Conforming — the research follows ethical guidelines","D. Communicable — the research is accessible to other teachers"],a:"B",e:"When other teachers adopt and test the strategy, the findings move toward GENERALIZABILITY (external validity) — the CONTRIBUTORY criterion's generalizable sub-criterion. The original research was situational, but as multiple teachers test it in different contexts, generalizability is being examined."},
  {id:"ie-258",d:"moderate",t:"Special Education vs. Inclusive Education Philosophy",q:"A parent says: 'My child needs SPECIAL EDUCATION, not Inclusive Education — they are different and incompatible.' The MOST ACCURATE response is:",c:["A. The parent is correct — they are mutually exclusive","B. SPECIAL NEEDS EDUCATION (IEP, specialized services) and INCLUSIVE EDUCATION (mainstream setting) are COMPLEMENTARY, not opposed. Inclusive Education uses SPECIAL EDUCATION METHODS AND SERVICES (IEP, accommodations) — it just DELIVERS THEM IN MAINSTREAM SETTINGS rather than segregated ones","C. Special education is superior to inclusive education for all students","D. Inclusive education has completely replaced special education"],a:"B",e:"COMPLEMENTARY, not contradictory: INCLUSIVE EDUCATION uses SPECIAL EDUCATION TOOLS (IEP, therapies, specialized instruction) but delivers them in MAINSTREAM SETTINGS. RA 11650 explicitly includes the term 'and Services for Learners with Disabilities' — specialized services continue, just in inclusive contexts."},
  {id:"ie-259",d:"moderate",t:"Visual Impairment and Assistive Technology",q:"A student with partial visual impairment needs to access textbooks. The teacher provides: (1) Digital textbooks on a tablet with adjustable font size, (2) Text-to-speech software, (3) Magnification software. These are examples of:",c:["A. Modifications — the curriculum content has been changed","B. Adaptations — more significant than modifications","C. ACCOMMODATIONS — assistive technology changes HOW the student accesses textbooks WITHOUT CHANGING the content or academic standards","D. IEP Goals — specific aspirations for the school year"],a:"C",e:"ASSISTIVE TECHNOLOGY = ACCOMMODATION. Digital textbooks with adjustable font, text-to-speech, magnification = changes in ACCESS FORMAT without changing the CONTENT, CURRICULUM, or ACADEMIC STANDARDS. Technology is a powerful accommodation tool for visual impairments."},
  {id:"ie-260",d:"moderate",t:"Friedreich's Ataxia Application",q:"A student with Friedreich's Ataxia has loss of coordination, slurred speech, and fatigue that worsens with physical activity. Which combination of accommodations is MOST APPROPRIATE for physical education class?",c:["A. Remove the student from all PE activities with no alternatives","B. Require the student to participate in all PE activities to build strength","C. EXEMPTION from tiring/heavy physical activities, ADAPTED ACTIVITIES matching current ability, EXTENSIONS for completing tasks, ACCESSIBLE SEATING, and PEER SUPPORT for movement as needed","D. Reduce PE to once per week for the student"],a:"C",e:"Friedreich's Ataxia: coordination loss + fatigue = PE accommodations. EXEMPTION from tiring activities, ADAPTED ACTIVITIES, EXTENSIONS for task completion, ACCESSIBLE SEATING, PEER SUPPORT. Maintain participation but REMOVE the activity demands that exceed physical capacity."},
  {id:"ie-261",d:"moderate",t:"Action Research and Teacher Development",q:"A curriculum specialist argues: 'Action research makes teachers into REFLECTIVE PRACTITIONERS rather than passive implementers of others' strategies.' This argument BEST supports which characteristic of action research?",c:["A. Participative — teachers and learners as co-researchers","B. Rigorous — following empirical study rules","C. REFLECTIVE — teachers continuously reflect on their own practice, evaluate what works, and modify approaches based on evidence from their own classroom","D. Situational — specific to teaching context"],a:"C",e:"REFLECTIVE PRACTITIONERS = teachers who CONTINUOUSLY REFLECT ON AND ACT UPON their own practice. Action research's REFLECTIVE characteristic makes teachers active inquirers into their own teaching — continuously improving rather than passively following external prescriptions."},
  {id:"ie-262",d:"moderate",t:"Inclusive Education and Non-disabled Benefits",q:"Research shows non-disabled students in inclusive classrooms develop stronger SOCIAL-EMOTIONAL SKILLS than peers in non-inclusive classrooms. The MOST LIKELY explanation is:",c:["A. Inclusive classrooms have lower academic expectations for all students","B. Non-disabled students learn FROM DISABLED PEERS AND TEACHERS how to handle challenges, develop patience, empathy, and advocacy skills through authentic inclusive interactions — building social-emotional competencies impossible in homogeneous classrooms","C. Non-disabled students receive more attention in inclusive classrooms","D. Inclusive classrooms have better-funded programs benefiting all students"],a:"B",e:"SOCIAL-EMOTIONAL DEVELOPMENT from authentic inclusion: non-disabled students develop EMPATHY (perspective-taking), PATIENCE (working with diverse learners), ADVOCACY SKILLS (supporting peers), and APPRECIATION FOR DIVERSITY — impossible to fully develop without authentic inclusive experiences."},
  {id:"ie-263",d:"moderate",t:"ORPA and School Context",q:"A teacher conducts ORPA Action Research on improving the reading performance of students with dyslexia in her class. After the first ORPA cycle (using phonics instruction), she sees 60% improvement. She is not satisfied with only 60% and plans another cycle. What does this decision illustrate?",c:["A. The teacher is being too perfectionistic — 60% is sufficient","B. The CYCLICAL AND RECURSIVE NATURE of action research — partial improvement = incomplete solution = NEW ORPA CYCLE with refined strategies to address the remaining 40% who did not improve","C. The teacher should switch to traditional research methods","D. 60% improvement means the strategy failed and should be abandoned"],a:"B",e:"CYCLICAL AND RECURSIVE (McNiff & Whitehead, 2006) — 60% improvement = PARTIAL SUCCESS. New ORPA cycle: Observe (who didn't improve?), Reflect (why didn't phonics work for them?), Plan (different strategy for remaining 40%), Act (implement). CYCLES CONTINUE until satisfactory resolution."},
  {id:"ie-264",d:"moderate",t:"Philippine IE Legal Framework",q:"A Grade 2 teacher discovers a student has LEARNING DISABILITIES but has never been evaluated or supported. Under RA 11650, what is the school's LEGAL OBLIGATION?",c:["A. Wait for the parents to formally request special education services","B. Move the student to a special school immediately","C. THE SCHOOL MUST IDENTIFY THE STUDENT'S SPECIAL NEEDS (through evaluation/assessment) and provide FREE BASIC AND QUALITY EDUCATION with appropriate supports — RA 11650 places the identification and support obligation on the SCHOOL, not only the parent","D. Only report the case to DepEd central office"],a:"C",e:"RA 11650: SCHOOL OBLIGATION = IDENTIFY learners with special needs AND provide free basic quality education. The school cannot wait passively — it must proactively IDENTIFY (through assessment) and PROVIDE SUPPORTS. This is a school-level obligation, not solely parent-initiated."},
  {id:"ie-265",d:"moderate",t:"IEP Goals Measurability",q:"An IEP Goal states: 'Juan will improve in reading.' A special education expert says this goal is INADEQUATE. Why, and what is a BETTER example?",c:["A. It is inadequate because it is too long","B. It is inadequate because GOOD IEP GOALS must be SPECIFIC AND MEASURABLE — 'Juan will improve' is unmeasurable. Better: 'By March 2025, Juan will read 3rd grade passages at 80 words per minute with 85% comprehension accuracy'","C. It is adequate because it identifies the student and subject area","D. IEP goals don't need to be specific — they are aspirational only"],a:"B",e:"IEP GOALS must be SPECIFIC AND MEASURABLE (SMART). 'Will improve in reading' = no baseline, no target, no timeline, no measurement method = unmeasurable. Better goal includes: WHO, WHEN, WHAT SKILL, AT WHAT LEVEL, MEASURED HOW — making progress objectively trackable."},
  {id:"ie-266",d:"moderate",t:"Action Research vs. Lesson Study",q:"A teacher asks: 'Is doing a LESSON STUDY (collaborative lesson planning and observation) the same as ACTION RESEARCH?' The MOST ACCURATE answer is:",c:["A. Yes — all collaborative teacher inquiry is action research","B. LESSON STUDY and Action Research OVERLAP but are distinct: Lesson Study focuses on refining ONE LESSON through collaborative planning/observation. Action Research is a broader CYCLICAL PROCESS of identifying problems, implementing strategies, and evaluating improvement in one's OWN PRACTICE over time","C. Lesson Study is superior to Action Research","D. Action Research requires formal academic training; Lesson Study does not"],a:"B",e:"RELATED BUT DISTINCT: Lesson Study = collaborative refinement of a specific lesson. Action Research = broader ORPA cycle of investigating and improving one's own practice over time. Lesson Study can be PART of an action research cycle (Plan/Act stages) but is not identical to it."},
  {id:"ie-267",d:"moderate",t:"Orthopedic Impairment Application",q:"A student with SPINA BIFIDA uses a wheelchair and has incomplete spinal cord formation. Her teacher asks: 'What are the TOP THREE classroom priorities?' Which answer is MOST COMPREHENSIVE?",c:["A. Provide notes and extend test time only","B. Seat at the back to avoid blocking others","C. (1) CLASSROOM ACCESSIBILITY (clear pathways for wheelchair), (2) ACCESSIBLE DESK AND MATERIALS (wheelchair-height table), (3) TASK SELECTION (assign tasks she can physically do, provide exemptions for tasks requiring intact mobility)","D. Remove the student from the classroom for all activities"],a:"C",e:"TOP THREE for SPINA BIFIDA/WHEELCHAIR: (1) ACCESSIBLE CLASSROOM (clear pathways, no obstructions), (2) ACCESSIBLE DESK AND MATERIALS (correct height for wheelchair), (3) APPROPRIATE TASK SELECTION (do-able tasks + exemption from physically impossible ones). These directly address the spinal cord/mobility impairment's educational impact."},
  {id:"ie-268",d:"moderate",t:"Adaptation Advanced Application",q:"A student with MULTIPLE DISABILITIES (intellectual disability + deafness) has needs so complex that neither standard modification nor accommodation is sufficient. The teacher redesigns EVERYTHING — new activities, new product requirements, new learning environment setup, new instructional process. This MOST CLOSELY describes:",c:["A. Accommodation — changes in access without changing content","B. Modification — lowering the difficulty level","C. ADAPTATION — a MORE SIGNIFICANT CHANGE in content, process, products, AND learning environment. More comprehensive than both accommodation and modification","D. IEP development — creating the personalized plan"],a:"C",e:"ADAPTATION = MORE SIGNIFICANT CHANGE in CONTENT, PROCESS, PRODUCTS, AND LEARNING ENVIRONMENT — more comprehensive than modification (difficulty level only) and accommodation (access only). For multiple disabilities with complex needs, adaptation (redesigning ALL dimensions) is required."},
  {id:"ie-269",d:"moderate",t:"Inclusive Education Research",q:"A critic says: 'Students with severe disabilities in inclusive classrooms take up disproportionate teacher time, harming non-disabled students.' The MOST RESEARCH-SUPPORTED rebuttal is:",c:["A. The critic is correct — this is always a problem in inclusive classrooms","B. Research shows that CO-TEACHING (providing a second teacher) and UNIVERSAL DESIGN FOR LEARNING (designing for all) eliminate this concern by ensuring BOTH teachers address diverse needs SIMULTANEOUSLY, benefiting all students rather than taking time from any","C. The critic is correct — only mild disabilities should be in inclusive settings","D. Teachers should give equal time to all students regardless of need"],a:"B",e:"CO-TEACHING + UDL are the evidence-based solutions: Co-teaching = additional teacher so NO student monopolizes one teacher's time. UDL = proactive universal design serves all students. Research on co-teaching shows NON-DISABLED students ALSO BENEFIT — more individualized attention, differentiated instruction, richer learning environment."},
  {id:"ie-270",d:"moderate",t:"Action Research Future-Oriented Application",q:"A teacher completes action research that improves student reading. Her principal asks: 'What happens after this research?' The response that BEST reflects the FUTURE-ORIENTED characteristic is:",c:["A. The research is done — no further action needed","B. The findings should be locked in the teacher's portfolio","C. The research LEADS TO FUTURE IMPROVEMENT: (1) teacher continues refining the strategy through NEW ORPA cycles, (2) findings are shared to inspire OTHERS' action research, (3) effective strategies become SCHOOL POLICY or PROGRAM recommendations — ongoing improvement cycle","D. The teacher should conduct the same research again next year without changes"],a:"C",e:"FUTURE-ORIENTED = seeks solution to CURRENT PROBLEM FOR FUTURE IMPROVEMENT. After one cycle: (1) CONTINUE ORPA cycles for ongoing refinement, (2) SHARE findings (participative + communicable), (3) CONTRIBUTE to POLICY/PROGRAMS (conforming/sustainable). Action research is not a one-time event — it is an ONGOING IMPROVEMENT PROCESS."},
  {id:"ie-271",d:"moderate",t:"Comprehensive IE Review",q:"A new teacher asks: 'What is the SIMPLEST way to remember the difference between Accommodation, Modification, and Adaptation?' The MOST HELPFUL mnemonic explanation is:",c:["A. All three are the same — they are synonyms","B. ACCOMMODATION = SAME content, different STRATEGY (access). MODIFICATION = LOWER content (lower difficulty). ADAPTATION = REDESIGN EVERYTHING (most significant change). Think: A-M-A in ascending order of how much you change the curriculum","C. Accommodation is for mild, Modification for moderate, Adaptation for severe disabilities — matching disability severity","D. Accommodation is for physical disabilities, Modification for learning disabilities, Adaptation for intellectual disabilities"],a:"B",e:"AMA Mnemonic: ACCOMMODATION = SAME content, different access strategy. MODIFICATION = LOWER difficulty level. ADAPTATION = REDESIGN EVERYTHING (content + process + products + environment). They are in ascending order of HOW MUCH the curriculum is changed — not based on disability severity."},
  {id:"ie-272",d:"moderate",t:"IDEA Categories Application",q:"A student who survived a traumatic car accident now has difficulty concentrating, impulsive behavior, and is 2 grade levels behind in all subjects. Before the accident she was a top student. Under IDEA, the PRIMARY DISABILITY category is:",c:["A. Emotional Disturbance — impulsive behavior","B. Learning Disability — academic delay","C. ADHD — concentration and impulsivity","D. TRAUMATIC BRAIN INJURY (TBI) — acquired brain injury from external physical force; all current symptoms are consistent with TBI sequelae"],a:"D",e:"TBI is the PRIMARY category — ACQUIRED injury to the brain from EXTERNAL PHYSICAL FORCE (car accident). TBI causes concentration difficulty, impulsivity, and academic regression — all symptoms are TBI SEQUELAE. Emotional symptoms and academic delays are consequences of TBI, not independent diagnoses."},
  {id:"ie-273",d:"moderate",t:"Social Model in Classroom",q:"A teacher redesigns her classroom to include: ramps (for wheelchair users), visual schedules (for ASD students), captioned videos (for deaf students), and flexible seating (for ADHD students). This universal redesign reflects the Social Model because:",c:["A. It diagnoses and treats each student's condition individually","B. It removes all disability from students through environmental design","C. It REMOVES ENVIRONMENTAL BARRIERS that disable students — making the environment accessible to ALL rather than requiring each student to overcome barriers created by a standard classroom design","D. It only benefits students with disabilities, not the whole class"],a:"C",e:"SOCIAL MODEL in classroom design: REMOVE ENVIRONMENTAL BARRIERS. Ramps (mobility barrier), visual schedules (sensory processing barrier), captions (hearing barrier), flexible seating (attention/regulation barrier). Each change removes a CLASSROOM BARRIER — making the environment equitable without 'fixing' any student."},
  {id:"ie-274",d:"moderate",t:"RA 7277 and RA 9442",q:"A restaurant refuses to give the 20% PWD discount to a customer with a hearing impairment, claiming 'hearing impaired people don't qualify.' Is the restaurant correct?",c:["A. Yes — the 20% discount only applies to mobility-impaired persons","B. Yes — the discount only applies to those with visible disabilities","C. NO — RA 7277 (as amended by RA 9442) grants the 20% discount to ALL DISABLED PERSONS including those with hearing impairments, mental conditions, and other types of disability — not only mobility impairments","D. Yes — hearing impairment is classified under Emotional Disturbance, not disability"],a:"C",e:"RA 7277 (amended by RA 9442) grants 20% discount to ALL DISABLED PERSONS — including hearing impaired, visually impaired, intellectually disabled, and all other disability types. The discount is for ALL qualified PWDs, not just visible or mobility impairments."},
  {id:"ie-275",d:"moderate",t:"Action Research and Inclusive Education Integration",q:"A special education teacher conducts action research on whether using SIGN LANGUAGE alongside oral instruction improves learning outcomes for a DEAF student in an inclusive classroom. The research uses the ORPA cycle and satisfies all 4Cs. This BEST illustrates:",c:["A. A teacher abandoning inclusive education in favor of SPED methods","B. A conflict between action research and inclusive education principles","C. ACTION RESEARCH SUPPORTING INCLUSIVE EDUCATION — the teacher uses rigorous inquiry (action research) to find effective ACCOMMODATIONS (sign language = accommodation) that improve a deaf student's outcomes in an INCLUSIVE setting","D. An illegal research project that requires IRB approval before starting"],a:"C",e:"PERFECT INTEGRATION: Action Research (systematic, reflective, ORPA, 4Cs) + Inclusive Education (accommodation in inclusive classroom) + Disability category application (deaf = hearing impairment). The teacher uses ACTION RESEARCH to find the best ACCOMMODATIONS for INCLUSIVE EDUCATION — all three frameworks working together."},
  {id:"ie-276",d:"moderate",t:"Inclusive Classroom Environment",q:"Under inclusive classroom guidelines, which practice MOST DIRECTLY addresses the 'ORGANIZATION' guideline?",c:["A. Using sign language with deaf students","B. Seating students with mobility impairments near accessible exits","C. Arranging shelves at multiple heights, using labeling systems all students can read, and providing manipulatives accessible to all — ENSURING ACCESSIBILITY OF MATERIALS AND ENGAGING ACTIVITIES FOR ALL LEARNERS","D. Conducting regular parent-teacher conferences"],a:"C",e:"ORGANIZATION guideline: ENSURE ACCESSIBILITY OF MATERIALS AND ENGAGING ACTIVITIES FOR ALL LEARNERS. This means: materials at reachable heights, accessible labels, manipulatives all students can use. The guideline is about PHYSICAL AND LOGISTICAL accessibility of classroom materials."},
  {id:"ie-277",d:"moderate",t:"Autism and Routine",q:"A student with ASD becomes extremely distressed when the daily classroom schedule changes unexpectedly. The teacher asks: 'Why does this student need ROUTINES?' The MOST ACCURATE explanation is:",c:["A. Students with ASD are stubborn and refuse to adapt","B. ASD involves RESTRICTED AND REPETITIVE BEHAVIORS — predictable routines reduce anxiety and provide the structured, predictable environment these students need for effective learning. Unexpected changes disrupt the student's regulatory system","C. All students need routines — there is nothing specific to ASD","D. Routines make teaching easier for teachers, not specifically for ASD students"],a:"B",e:"ASD TRIAD: RESTRICTED AND REPETITIVE WAY OF BEING-IN-THE-WORLD includes insistence on routine/sameness. PREDICTABLE ROUTINE reduces ANXIETY and supports REGULATION — without it, ASD students cannot effectively engage with learning. Routine = accommodation for ASD's neurological need for predictability."},
  {id:"ie-278",d:"moderate",t:"IE Summary Application",q:"A principal evaluates whether her school is TRULY INCLUSIVE. She sees students with disabilities PHYSICALLY PRESENT in regular classrooms but: no IEPs, no accommodations, no co-teaching, no teacher training. She concludes this is NOT true inclusion. She is CORRECT because:",c:["A. Physical presence alone IS sufficient for inclusion","B. PHYSICAL PLACEMENT without APPROPRIATE SUPPORTS (IEP, accommodations, co-teaching, teacher training) is INTEGRATION, not INCLUSION. True inclusion requires both physical placement AND comprehensive individualized supports","C. Non-disabled students are not benefiting either","D. The principal is wrong — having students present is enough"],a:"B",e:"INTEGRATION (physical placement only) ≠ INCLUSION (physical placement + comprehensive supports). TRUE INCLUSION requires: PHYSICAL PLACEMENT + IEP + ACCOMMODATIONS + CO-TEACHING + TEACHER TRAINING + UDL. Without supports, students with disabilities are present but NOT truly included in learning."},
  {id:"ie-279",d:"moderate",t:"Action Research Design",q:"A teacher wants to ensure her action research is CREDIBLE (Transparent sub-criterion). Which practice MOST directly addresses this?",c:["A. Publishing in an international journal","B. Getting approval from the DepEd superintendent","C. CLEARLY DOCUMENTING ALL RESEARCH METHODS, DATA COLLECTION PROCEDURES, AND DECISION-MAKING STEPS so that her research CAN BE EXAMINED OR REPLICATED by others based on her truthful documentation","D. Including at least 100 participants in the study"],a:"C",e:"TRANSPARENT (sub-criterion of Credible): research method can be EXAMINED OR REPLICATED based on the researcher's TRUTHFUL DOCUMENTATION. Clear documentation of ALL methods, data collection, and decisions = transparent = credible. Others should be able to follow her exact process."},
  {id:"ie-280",d:"moderate",t:"Inclusion Best Practices",q:"A school claims to be 'inclusive' but uses different criteria to evaluate students with disabilities: lower grades are 'acceptable' for them while higher standards apply to non-disabled peers. An inclusion specialist says this is NOT true inclusion. Why?",c:["A. Inclusive education always requires identical standards for all","B. The specialist is correct — while ACCOMMODATIONS change access, the SCHOOL SHOULD NOT lower standards for disabled students WITHOUT an IEP SPECIFYING MODIFICATIONS. Informally lowering standards without an IEP creates a two-tier system that is neither equitable nor legally appropriate","C. The specialist is wrong — adjusting standards is always acceptable in inclusive settings","D. Different evaluation criteria are always acceptable for diverse learners"],a:"B",e:"KEY ISSUE: Informal lowering of standards WITHOUT AN IEP = NOT INCLUSIVE PRACTICE and NOT LEGAL. If a student needs MODIFIED standards, this must be SPECIFIED IN THE IEP (with team agreement + parent consent). Informal different standards = discrimination without accountability or individualization."},

  // ==================== DIFFICULT (20) ====================
  {id:"ie-281",d:"difficult",t:"Legal and Philosophical Integration",q:"A critic argues: 'Philippine inclusive education laws are contradictory — BP 344 focuses on PHYSICAL ACCESS while RA 11650 focuses on EDUCATIONAL ACCESS. You cannot implement both simultaneously.' The MOST INTELLECTUALLY RIGOROUS response is:",c:["A. The critic is correct — the laws address different things and cannot coexist","B. The laws are COMPLEMENTARY, not contradictory: BP 344 ensures PHYSICAL ACCESS (entering buildings, using facilities) which is a PREREQUISITE for RA 11650's EDUCATIONAL ACCESS. Without BP 344's physical access, RA 11650's educational inclusion is impossible. Together they create a CONTINUUM of access from physical to educational","C. RA 11650 supersedes BP 344 — the newer law replaces the older one","D. Only one law can be implemented at a time in a school"],a:"B",e:"COMPLEMENTARY CONTINUUM: BP 344 (physical access) + RA 11650 (educational access) = COMPLETE ACCESS. Without physical access (BP 344), educational access (RA 11650) cannot be achieved — a student who cannot enter the building cannot be educated there. Physical access is the PREREQUISITE for educational access."},
  {id:"ie-282",d:"difficult",t:"IDEA Advanced Application",q:"A student has EMOTIONAL DISTURBANCE (bipolar disorder) AND LEARNING DISABILITY (dyslexia). She qualifies under BOTH categories. The IEP team debates: 'Which category is PRIMARY for IEP eligibility?' The MOST EDUCATIONALLY SOUND approach is:",c:["A. Always choose the most recently diagnosed condition","B. Always choose the most severe condition","C. Choose the category that HAS THE GREATEST CURRENT EDUCATIONAL IMPACT — if bipolar disorder is causing more academic disruption currently, prioritize that. The IEP must address BOTH regardless of eligibility category. Reassess annually as circumstances change","D. Only one category can be listed — flip a coin if equal impact"],a:"C",e:"EDUCATIONAL IMPACT determines primary eligibility category. Choose what has GREATEST CURRENT EDUCATIONAL IMPACT. IEP must ADDRESS ALL AREAS OF IMPACT regardless of the eligibility category chosen. Annual review allows changing the primary category if the relative impact of conditions shifts."},
  {id:"ie-283",d:"difficult",t:"Action Research Ethics Advanced",q:"A teacher wants to conduct action research comparing two reading interventions: one group gets 'phonics-based instruction' (new strategy), the other gets 'traditional instruction' (control). Both groups are from the same school. An ethics advisor says: 'If phonics proves more effective mid-study, you must switch the control group to phonics immediately.' This advice reflects:",c:["A. Poor research design — you cannot change designs mid-study","B. ETHICAL OBLIGATION (Conforming/Ethical) — when a beneficial intervention is identified DURING research, continuing to withhold it from control participants (who are also your students) is ethically unjustified. Students' welfare outweighs research design purity in action research","C. Bad advice — research design integrity must be maintained","D. Only applicable to medical research, not educational research"],a:"B",e:"ETHICAL ACTION RESEARCH PRINCIPLE: student welfare > research design purity. If the new strategy proves beneficial mid-study, withholding it from the control group (your students) violates the ETHICAL sub-criterion of CONFORMING. Action research by teachers has heightened ethical obligations because the 'participants' are their own students."},
  {id:"ie-284",d:"difficult",t:"Co-teaching Advanced Design",q:"A school implements co-teaching with TWO TEACHERS who have VERY DIFFERENT EXPERTISE: Teacher A is a general educator (strong in content), Teacher B is a special educator (strong in disability pedagogy). What co-teaching model MOST effectively leverages BOTH expertise types for an inclusive Science class?",c:["A. One Teach, One Observe — Teacher A teaches; Teacher B observes always","B. TEAM TEACHING — both ACTIVELY PARTICIPATE, providing complementary inputs: Teacher A delivers content expertise, Teacher B simultaneously provides pedagogical adaptations, scaffolding, and supports for diverse learners. Both monitor and facilitate together","C. Alternative Teaching — Teacher A teaches large group, Teacher B teaches special ed students separately","D. Parallel Teaching — both teach the same content to separate groups"],a:"B",e:"TEAM TEACHING maximally leverages COMPLEMENTARY EXPERTISE: Teacher A's CONTENT EXPERTISE + Teacher B's DISABILITY PEDAGOGY expertise = students receive SIMULTANEOUSLY both rigorous content AND appropriate learning supports. Teacher A teaches; Teacher B adapts/scaffolds IN REAL TIME for all learners. Maximum collaboration."},
  {id:"ie-285",d:"difficult",t:"IEP and FAPE Advanced",q:"An IEP specifies that a student with autism should receive 30 minutes of SPEECH THERAPY daily. The school only provides 15 minutes due to therapist availability. The parent files a complaint. From an IDEA-BASED LEGAL ANALYSIS:",c:["A. The school is justified — they provided some speech therapy","B. The parent is CORRECT to complain: the IEP is a LEGAL CONTRACT. IDEA guarantees FAPE — which includes providing ALL SPECIFIED SERVICES. The school's delivery of HALF the specified service is a VIOLATION of the IEP and of FAPE. The school must find a way to provide the full 30 minutes (hire additional therapist, use telepractice, etc.)","C. 15 minutes is close enough — substantial compliance","D. Only courts can determine if this is a FAPE violation"],a:"B",e:"IEP = LEGAL CONTRACT. FAPE includes ALL services SPECIFIED in the IEP. 15 minutes when 30 is specified = IEP VIOLATION + potential FAPE violation. The school MUST provide the FULL specified service — find additional therapist, use telepractice, contract with private provider. 'Lack of staff' does not excuse FAPE violations."},
  {id:"ie-286",d:"difficult",t:"Comprehensive Disability Analysis",q:"A student shows: (1) cannot process reading (Dyslexia), (2) makes sounds and movements involuntarily (possibly Tourette's, classified under Other Health Impairments), (3) severe anxiety about school (Emotional Disturbance). An IEP team must design comprehensive supports. The MOST SOPHISTICATED IEP would include:",c:["A. Focus on one disability only to avoid overwhelming the student","B. TIER 1: Accommodations for DYSLEXIA (text-to-speech, extended time, oral assessment options). TIER 2: Accommodations for OHI/TOURETTE'S (seating away from high-traffic, non-punitive response to involuntary tics). TIER 3: Emotional/behavioral support for ANXIETY (counseling, quiet space access, anxiety management strategies). ALL ADDRESSED SIMULTANEOUSLY","C. Refer to three separate specialists and wait for their reports before any classroom support","D. Place in a special school that can address all three simultaneously"],a:"B",e:"COMPREHENSIVE MULTI-DISABILITY IEP: Each disability requires its own domain of support simultaneously. DYSLEXIA = access accommodations. TOURETTE'S/OHI = behavioral accommodations (non-punitive, seating). ANXIETY/ED = emotional/behavioral supports. ALL THREE OPERATE SIMULTANEOUSLY in the inclusive classroom — not sequentially or in separate settings."},
  {id:"ie-287",d:"difficult",t:"Action Research 4Cs Integration",q:"A researcher asks: 'Can a piece of action research be CREDIBLE but NOT COMMUNICABLE?' Give the MOST ANALYTICALLY RIGOROUS answer.",c:["A. No — the four Cs always come together or not at all","B. YES — a research study can be INTERNALLY RIGOROUS (credible: rigorous, transparent, consistent) but written in highly technical jargon that only specialists understand (not consumable) or stored in inaccessible archives (not accessible). CREDIBILITY is about research quality; COMMUNICABILITY is about dissemination quality — they are separable","C. The question is irrelevant — all four Cs are identical","D. No — credibility automatically makes research communicable"],a:"B",e:"ANALYTICALLY: YES, they are SEPARABLE. CREDIBLE = internal research quality (rigor, transparency, consistency). COMMUNICABLE = dissemination quality (consumable format, accessible venue). A brilliant, rigorous study written in inaccessible jargon and locked in a file drawer = CREDIBLE but NOT COMMUNICABLE. The 4Cs are DISTINCT criteria, each requiring separate attention."},
  {id:"ie-288",d:"difficult",t:"Inclusion Policy and Practice Gap",q:"A national audit finds: 95% of Philippine public schools are LEGALLY COMPLIANT with RA 11650 (have accepted learners with disabilities), but only 20% show EFFECTIVE INCLUSION (students with disabilities show academic and social growth). What does this 95% vs. 20% gap indicate?",c:["A. RA 11650 is poorly written and should be repealed","B. Only 20% of students with disabilities are capable of inclusion","C. LEGAL COMPLIANCE (physical enrollment) ≠ EFFECTIVE INCLUSION (genuine educational engagement). The gap reveals IMPLEMENTATION QUALITY is the critical issue — presence without appropriate supports, trained teachers, UDL, co-teaching, and genuine pedagogical inclusion = enrollment without education","D. 95% compliance is excellent — 20% effective inclusion is acceptable"],a:"C",e:"This gap is the definitive evidence that PHYSICAL PLACEMENT ≠ INCLUSION. 75% of schools have students with disabilities enrolled (legal compliance) but do not actually INCLUDE them (no growth). True inclusion requires: trained teachers, IEPs, accommodations, UDL, co-teaching, assessment modification — not just enrollment numbers."},
  {id:"ie-289",d:"difficult",t:"Advanced Inclusive Education Philosophy",q:"An inclusive education scholar argues: 'Inclusive education is not ABOUT DISABILITY — it is about creating schools that WORK FOR ALL CHILDREN.' The DEEPEST MEANING of this statement is:",c:["A. Inclusive education ignores students with disabilities","B. Only non-disabled students benefit from inclusive approaches","C. THE DEEPEST MEANING: Inclusion is about transforming SCHOOL SYSTEMS to be responsive to ALL LEARNERS' diversity — not just accommodating disability. When schools are designed for the full range of human diversity (UDL, flexible pedagogy, responsive assessment), EVERYONE benefits. Disability is ONE dimension of human diversity, not the only reason for inclusive transformation","D. Inclusion is idealistic and impossible in practice"],a:"C",e:"DEEPEST INCLUSION PHILOSOPHY: Designing for disability = designing for the EXTREME ENDS of human variation = design that works for EVERYONE. UDL, flexible pedagogy, responsive assessment = better schools for ALL. The scholar is articulating the UNIVERSAL BENEFIT principle — inclusively designed schools don't just accommodate disability; they create better learning for ALL."},
  {id:"ie-290",d:"difficult",t:"Action Research and Inclusive Education Integration Advanced",q:"A teacher conducts PARTICIPATORY ACTION RESEARCH involving a student with intellectual disability as a CO-RESEARCHER in designing accommodations for her own learning. The student helps observe, reflect on what works, and plan her own supports. This approach is ADVANCED because it simultaneously demonstrates:",c:["A. Only the Participative characteristic of action research","B. Only inclusive education's self-advocacy goal","C. SIMULTANEOUS DEMONSTRATION OF: (1) PARTICIPATIVE AR (student as co-researcher), (2) REFLECTIVE AR (student reflects on own learning = metacognition = Assessment AS Learning parallel), (3) INCLUSIVE EDUCATION (student with ID actively shapes her own educational environment), (4) SELF-ADVOCACY (student directing her own support design), (5) FUTURE-ORIENTED (student-designed supports improve future learning)","D. An inappropriate research design — students with intellectual disability cannot be researchers"],a:"C",e:"MOST ADVANCED INTEGRATION: (1) PARTICIPATIVE AR (student is co-researcher), (2) REFLECTIVE AR (student's metacognitive reflection on own learning), (3) INCLUSIVE EDUCATION PHILOSOPHY (student with ID as active agent), (4) SELF-ADVOCACY (student participates in designing own supports), (5) FUTURE-ORIENTED (student-designed supports = sustained improvement). All five dimensions simultaneously."},
  {id:"ie-291",d:"difficult",t:"WHO Impairment-Disability-Handicap Advanced",q:"A student born deaf (IMPAIRMENT) in a school with NO hearing support (HANDICAP) learns PERFECTLY through sign language and deaf education methods, graduates with honors, and functions independently. This case is MOST ACCURATELY analyzed as:",c:["A. The student overcame their disability through personal effort","B. The student has no disability — deaf people are not disabled","C. IMPAIRMENT REMAINS but DISABILITY IS MINIMAL (sign language provides full language access) and HANDICAP IS ADDRESSED (supportive school environment). The Social Model succeeded: environmental design (sign language education + supportive school) ELIMINATED THE EDUCATIONAL HANDICAP despite the unchanged IMPAIRMENT","D. This case is impossible — deafness always causes educational disability"],a:"C",e:"SOCIAL MODEL SUCCESS: (1) IMPAIRMENT unchanged (born deaf), (2) DISABILITY MINIMIZED (sign language = full language access = no task limitation for communication), (3) HANDICAP ELIMINATED (supportive school + sign language = no situational disadvantage). Result: honors graduate who functions independently. The environment's COMPLETE REMOVAL OF BARRIERS produced full inclusion despite unchanged impairment."},
  {id:"ie-292",d:"difficult",t:"Action Research Generalizability vs. Situational Nature",q:"A researcher synthesizes 50 action research studies on inclusive education from 50 different Philippine public schools. She argues: 'While each study was situational, together they reveal TRANSFERABLE PRINCIPLES for inclusive education.' This approach is called:",c:["A. Traditional meta-analysis replacing action research","B. Invalid — action research cannot be synthesized","C. META-SYNTHESIS OF ACTION RESEARCH — aggregating multiple situational studies to identify TRANSFERABLE PATTERNS AND PRINCIPLES. This approach respects the situational nature of each study while extracting broader insights, bridging the gap between action research's situational limitation and the need for generalizable knowledge","D. A violation of action research ethics"],a:"C",e:"META-SYNTHESIS = synthesizing multiple situational action research studies to identify TRANSFERABLE PATTERNS. Individual AR = situational. 50 AR studies together = emerging TRANSFERABLE PRINCIPLES. This is how action research contributes to broader knowledge — through accumulation and synthesis, bridging the situated-generalized tension."},
  {id:"ie-293",d:"difficult",t:"Comprehensive IE Analysis",q:"The BIGGEST UNRESOLVED TENSION in inclusive education globally (including the Philippines) is between FULL INCLUSION (all students in regular classrooms always) and the CONTINUUM OF SERVICES (some students sometimes need specialized settings). The MOST PHILOSOPHICALLY AND EMPIRICALLY DEFENSIBLE position is:",c:["A. Full inclusion always — the LRE must always be a regular classroom","B. Specialized schools always — all students with disabilities need specialized settings","C. THE CONTINUUM OF SERVICES — LRE means the LEAST RESTRICTIVE ENVIRONMENT APPROPRIATE for THAT INDIVIDUAL student. For most students, this is full or partial regular classroom with supports. For a small subset with the most intensive needs, a specialized setting may temporarily be the LRE. The IEP team determines individually — not a blanket policy for all","D. There is no tension — both positions are identical"],a:"C",e:"CONTINUUM OF SERVICES is most defensible: LRE is INDIVIDUALIZED — most students = regular classroom with supports. A small subset = may need more specialized settings as temporary LRE. The key: IEP TEAM DETERMINATION based on INDIVIDUAL NEEDS, guided by LRE principle. Neither FULL INCLUSION nor FULL SEGREGATION as universal policy — individualized continuum."},
  {id:"ie-294",d:"difficult",t:"Philippine IE Advanced",q:"An education researcher claims: 'RA 11650 is well-intentioned but UNIMPLEMENTABLE in most Philippine public schools due to resource constraints.' A policy defender responds: 'RA 11650 built in mechanisms specifically to address resource constraints.' What are these BUILT-IN MECHANISMS?",c:["A. RA 11650 provides unlimited funding to all schools","B. RA 11650 only applies to well-resourced schools","C. RA 11650's built-in mechanisms: (1) ILRC (provides centralized support to many schools through one center), (2) VIRTUAL ILRC option (extends support to remote/resource-limited schools digitally), (3) DepEd mandate (existing school personnel trained), (4) All cities/municipalities as ILRC anchors (local government support), (5) Collaboration with RA 10524 employment incentives (building local expertise)","D. RA 11650 has no built-in mechanisms — it relies entirely on school budgets"],a:"C",e:"BUILT-IN MECHANISMS: (1) CENTRALIZED ILRC (one serves many schools), (2) VIRTUAL ILRC (remote digital support), (3) DepEd IMPLEMENTATION MANDATE (uses existing resources), (4) CITY/MUNICIPALITY ANCHOR (local government partnership), (5) RESOURCE-SHARING across schools through ILRC network. These mechanisms acknowledge resource constraints and provide SYSTEM-LEVEL solutions."},
  {id:"ie-295",d:"difficult",t:"Action Research Advanced Ethical Design",q:"A school principal wants ALL teachers to conduct action research as a requirement. A teacher objects: 'Forced action research violates the PARTICIPATIVE and ETHICAL principles of action research.' The teacher is PARTIALLY CORRECT because:",c:["A. The teacher is completely wrong — required action research is always ethical","B. The teacher is PARTIALLY CORRECT: PARTICIPATIVE AR requires VOLUNTARY engagement and GENUINE INQUIRY motivated by teachers' own questions about practice. MANDATED AR may produce compliance-driven research without genuine reflection or intent to change practice. HOWEVER, building a culture of inquiry (supporting, not just requiring, AR) can be legitimate","C. All mandatory teacher activities violate research ethics","D. The principal has absolute authority to mandate research"],a:"B",e:"PARTIALLY CORRECT: Action research's PARTICIPATIVE nature implies VOLUNTARY, GENUINE INQUIRY. MANDATED AR can produce SUPERFICIAL COMPLIANCE without genuine reflection. HOWEVER, building an INQUIRY CULTURE through support, modelling, and shared professional learning can legitimately cultivate action research dispositions — the distinction is between COMPLIANCE (bad) and CULTIVATED INQUIRY CULTURE (acceptable)."},
  {id:"ie-296",d:"difficult",t:"Integration of All IE Concepts",q:"A teacher can be considered an INCLUSIVE EDUCATION EXPERT when she demonstrates which COMPREHENSIVE set of competencies?",c:["A. Only knowledge of disability categories (IDEA)","B. Only skills in IEP development","C. COMPREHENSIVE COMPETENCY SET: (1) PHILOSOPHICAL (understands Medical vs. Social Model, rights-based approach), (2) LEGAL (knows and applies RA 11650, BP 344, IDEA, other laws), (3) PEDAGOGICAL (accommodations, modifications, adaptations, co-teaching, UDL), (4) INDIVIDUAL (IEP development, disability-specific teaching strategies), (5) REFLECTIVE (conducts action research on own inclusive practice), (6) COLLABORATIVE (works with parents, specialists, co-teachers)","D. Only certification in special education"],a:"C",e:"INCLUSIVE EDUCATION EXPERT requires ALL SIX DOMAINS: PHILOSOPHICAL (paradigm understanding), LEGAL (law knowledge and application), PEDAGOGICAL (AMA, co-teaching, UDL), INDIVIDUAL (IEP, disability-specific strategies), REFLECTIVE (action research on own practice), COLLABORATIVE (multi-stakeholder teamwork). Competency in only ONE area is insufficient."},
  {id:"ie-297",d:"difficult",t:"WHO and IDEA Integration",q:"A student has AUTISM (IDEA category) affecting communication and social skills. Using WHO's framework, her IMPAIRMENT (neurological differences) creates DISABILITY (difficulty in social communication tasks) which in an unsupportive classroom becomes HANDICAP (excluded from group activities). The teacher addresses all three levels using which approaches?",c:["A. Medical treatment for autism (impairment level)","B. IMPAIRMENT: cannot change, but understand it (autism = neurological). DISABILITY: ACCOMMODATE with visual supports, structured routine, explicit social skills teaching (reducing task-level limitations). HANDICAP: DESIGN INCLUSIVE CLASSROOM (Social Model) — structured groups, peer training, visual schedules — REMOVING ENVIRONMENTAL BARRIERS that exclude her","C. Place in special school (addresses all three levels)","D. Only address the handicap level — impairment and disability are medical issues"],a:"B",e:"THREE-LEVEL APPROACH: (1) IMPAIRMENT: neurological — cannot cure but UNDERSTAND it for planning. (2) DISABILITY: address task-level limitations through ACCOMMODATIONS (visual supports, routine, social skills teaching). (3) HANDICAP: DESIGN INCLUSIVE ENVIRONMENT (Social Model) removing barriers that exclude her. WHO framework + Social Model + IDEA accommodations = complete approach."},
  {id:"ie-298",d:"difficult",t:"Comprehensive Action Research and IE",q:"A research institute summarizes 10 years of Philippine school-based action research on inclusive education. The findings consistently show: (1) Teachers who conduct AR on inclusive practice become more effective inclusive educators. (2) Schools with AR cultures show higher student outcomes for BOTH disabled and non-disabled learners. (3) AR findings from multiple schools reveal transferable inclusive education strategies. What does this 10-year synthesis MOST POWERFULLY DEMONSTRATE?",c:["A. Action research is only useful for individual teachers","B. Inclusive education is only effective in certain schools","C. THE SYNERGISTIC RELATIONSHIP between ACTION RESEARCH and INCLUSIVE EDUCATION: AR makes teachers REFLECTIVE practitioners who CONTINUOUSLY IMPROVE inclusive practice. Improved inclusive practice benefits ALL learners. Multiple ARS reveal TRANSFERABLE PRINCIPLES that advance the field. AR + IE = MUTUALLY REINFORCING, SCHOOL-WIDE, SCALABLE IMPROVEMENT CYCLE","D. Traditional research is superior to action research for school improvement"],a:"C",e:"10-YEAR SYNTHESIS shows: AR → REFLECTIVE INCLUSIVE TEACHERS → BETTER OUTCOMES FOR ALL → TRANSFERABLE PRINCIPLES → FIELD-WIDE KNOWLEDGE BUILDING. This is the SYNERGISTIC RELATIONSHIP: AR improves inclusive practice → inclusive practice improves all learning outcomes → multiple ARS generate field-wide knowledge → field-wide knowledge improves future AR. A VIRTUOUS CYCLE of improvement."},
  {id:"ie-299",d:"difficult",t:"Philippine IE Legal Synthesis",q:"A student advocate creates a 'PWD Rights Map' showing how Philippine laws protect a PWD's rights from birth to employment. CORRECTLY map the following laws: (1) Right to access public spaces, (2) Right to quality education regardless of condition, (3) Right to inclusive education in public schools with support services, (4) Right to social discounts, (5) Right to employment opportunities.",c:["A. All laws are the same and cover all rights equally","B. (1) BP 344 (Accessibility — public spaces). (2) BP 232 (Education Act — quality education for all). (3) RA 11650 (Inclusive Education — public schools with ILRC). (4) RA 7277/RA 9442 (Magna Carta — 20% discount). (5) RA 10524 (Expanded PWD Positions — employment)","C. (1) RA 7277, (2) RA 11650, (3) BP 344, (4) BP 232, (5) RA 10524","D. All rights are covered only by RA 11650"],a:"B",e:"CORRECT PWD RIGHTS MAP: BP 344 (physical access/mobility). BP 232 (quality education for ALL, regardless of condition). RA 11650 (INCLUSIVE education in public schools + ILRC). RA 7277/9442 (Magna Carta + amendment = social rights + 20% discount). RA 10524 (employment positions for PWDs). Each law = one specific domain of PWD rights."},
  {id:"ie-300",d:"difficult",t:"Comprehensive IE and AR Final Synthesis",q:"A national policy on inclusive education requires EVERY PUBLIC SCHOOL to: (1) implement RA 11650, (2) use the IEP process, (3) train all teachers in accommodations/modifications/adaptations and co-teaching, (4) implement UDL, and (5) require each teacher to conduct at least one action research study on inclusive practice per school year. What is the ULTIMATE EDUCATIONAL RATIONALE for INCLUDING ACTION RESEARCH in this policy?",c:["A. Action research is required by DepEd for promotion purposes","B. Action research generates data for DepEd statistical reports","C. ACTION RESEARCH is the MECHANISM BY WHICH TEACHERS BECOME CONTINUOUSLY IMPROVING INCLUSIVE PRACTITIONERS — it transforms policy implementation from EXTERNAL COMPLIANCE to INTERNAL, REFLECTIVE PROFESSIONAL GROWTH. Teachers who research their own inclusive practice develop: deeper understanding of disability, evidence-based strategies, metacognitive awareness of teaching, and commitment to improvement. Without AR, inclusive education remains a policy requirement; with AR, it becomes a PROFESSIONAL CONVICTION","D. Action research is cheap and requires no resources"],a:"C",e:"ULTIMATE RATIONALE: Action research transforms policy COMPLIANCE → professional CONVICTION. Teachers who research their own inclusive practice develop: UNDERSTANDING (evidence-based disability knowledge), SKILLS (tested and refined strategies), REFLECTION (metacognitive teaching awareness), COMMITMENT (personally invested in what they researched). AR = the engine that sustains CONTINUOUS IMPROVEMENT in inclusive education beyond initial training."},
];
